        condition: nodes.Expr,
        singular: str,
        plural: t.Optional[str],
        fallback: str,
        variables: t.Dict[str, nodes.Expr],
        plural_expr: t.Optional[nodes.Expr],
        vars_referenced: bool,
        num_called_num: bool,
    ) -> nodes.If:
        """Generates the conditional translation/fallback node."""
        newstyle = self.environment.newstyle_gettext  # type: ignore
        trans_call: nodes.Expr

        # no variables referenced?  no need to escape for old style
        # gettext invocations only if there are vars.
        if not vars_referenced and not newstyle:
            singular = singular.replace("%%", "%")
            if plural:
                plural = plural.replace("%%", "%")
            fallback = fallback.replace("%%", "%")

        # singular only:
        if plural_expr is None:
            gettext = nodes.Name("gettext", "load")
            trans_call = nodes.Call(gettext, [nodes.Const(singular)], [], None, None)

        # singular and plural
        else:
            ngettext = nodes.Name("ngettext", "load")
            trans_call = nodes.Call(
                ngettext,
                [nodes.Const(singular), nodes.Const(plural), plural_expr],
                [],
                None,
                None,
            )

        # in case newstyle gettext is used, the method is powerful
        # enough to handle the variable expansion and autoescape
        # handling itself
        if newstyle:
            for key, value in variables.items():
                # the function adds that later anyways in case num was
                # called num, so just skip it.
                if num_called_num and key == "num":
                    continue
                trans_call.kwargs.append(nodes.Keyword(key, value))
            trans_expr: nodes.Expr = trans_call

        # otherwise do that here
        else:
            trans_expr = trans_call
            if variables:
                trans_expr = nodes.Mod(
                    trans_expr,
                    nodes.Dict(
                        [
                            nodes.Pair(nodes.Const(key), value)
                            for key, value in variables.items()
                        ]
                    ),
                )

        # mark the return value as safe if we are in an environment with
        # autoescaping turned on
        trans_expr = nodes.MarkSafeIfAutoescape(trans_expr)

        # the fallback is rendered directly, with variable substitution
        # but without going through gettext/ngettext at all
        fallback_expr: nodes.Expr = nodes.Const(fallback)
        if variables:
            fallback_expr = nodes.Mod(
                fallback_expr,
                nodes.Dict(
                    [
                        nodes.Pair(nodes.Const(key), value)
                        for key, value in variables.items()
                    ]
                ),
            )
        fallback_expr = nodes.MarkSafeIfAutoescape(fallback_expr)

        return nodes.If(
            condition,
            [nodes.Output([trans_expr])],
            [],
            [nodes.Output([fallback_expr])],
        )


